using Microsoft.AspNetCore.Identity;

namespace sv_58c318d9f2eb4018968630f3663ee0a8.Data;

public class ApplicationUser : IdentityUser
{
}

using Microsoft.AspNetCore.Identity.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore;

namespace sv_58c318d9f2eb4018968630f3663ee0a8.Data;

public class ApplicationDbContext : IdentityDbContext<ApplicationUser>
{
    public ApplicationDbContext(DbContextOptions<ApplicationDbContext> options)
        : base(options)
    {
    }
}

@page "/Account/Login"
@using System.ComponentModel.DataAnnotations
@using Microsoft.AspNetCore.Identity
@using sv_58c318d9f2eb4018968630f3663ee0a8.Data
@inject SignInManager<ApplicationUser> SignInManager
@inject NavigationManager Navigation

<PageTitle>Log in</PageTitle>

<div class="row justify-content-center">
    <div class="col-md-4">
        <h1>Log in</h1>

        @if (!string.IsNullOrEmpty(errorMessage))
        {
            <div class="alert alert-danger">@errorMessage</div>
        }

        <EditForm Model="Input" method="post" OnValidSubmit="LoginUser" FormName="login">
            <DataAnnotationsValidator />
            <ValidationSummary class="text-danger" role="alert" />

            <div class="form-floating mb-3">
                <InputText @bind-Value="Input.Email" class="form-control" autocomplete="username" placeholder="name@example.com" />
                <label for="email">Email</label>
                <ValidationMessage For="() => Input.Email" class="text-danger" />
            </div>

            <div class="form-floating mb-3">
                <InputText type="password" @bind-Value="Input.Password" class="form-control" autocomplete="current-password" placeholder="password" />
                <label for="password">Password</label>
                <ValidationMessage For="() => Input.Password" class="text-danger" />
            </div>

            <button type="submit" class="w-100 btn btn-lg btn-primary">Log in</button>
        </EditForm>
    </div>
</div>

@code {
    private string? errorMessage;

    [SupplyParameterFromForm]
    private LoginInput Input { get; set; } = new();

    [SupplyParameterFromQuery]
    private string? ReturnUrl { get; set; }

    private async Task LoginUser()
    {
        var result = await SignInManager.PasswordSignInAsync(Input.Email, Input.Password, isPersistent: false, lockoutOnFailure: false);
        if (result.Succeeded)
        {
            Navigation.NavigateTo(ReturnUrl ?? "/", forceLoad: true);
        }
        else
        {
            errorMessage = "Error: Invalid login attempt.";
        }
    }

    private sealed class LoginInput
    {
        [Required]
        [EmailAddress]
        public string Email { get; set; } = "";

        [Required]
        [DataType(DataType.Password)]
        public string Password { get; set; } = "";
    }
}

@page "/Account/Logout"
@using Microsoft.AspNetCore.Identity
@using sv_58c318d9f2eb4018968630f3663ee0a8.Data
@inject SignInManager<ApplicationUser> SignInManager
@inject NavigationManager Navigation

@code {
    [SupplyParameterFromForm]
    private string? Confirm { get; set; }

    protected override async Task OnInitializedAsync()
    {
        await SignInManager.SignOutAsync();
        Navigation.NavigateTo("/", forceLoad: true);
    }
}

@inject NavigationManager Navigation

@code {
    protected override void OnInitialized()
    {
        Navigation.NavigateTo($"Account/Login?ReturnUrl={Uri.EscapeDataString(Navigation.Uri)}", forceLoad: true);
    }
}

@page "/admin/users"
@rendermode InteractiveServer
@using Microsoft.AspNetCore.Authorization
@using Microsoft.AspNetCore.Identity
@using sv_58c318d9f2eb4018968630f3663ee0a8.Data
@attribute [Authorize(Roles = "Admin")]
@inject UserManager<ApplicationUser> UserManager

<PageTitle>User Management</PageTitle>

<h1>User Management</h1>
<p>Manage all users in the system.</p>

@if (userRoles is null)
{
    <p><em>Loading...</em></p>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Email</th>
                <th>Roles</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var entry in userRoles)
            {
                <tr>
                    <td>@entry.Email</td>
                    <td>@entry.Roles</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<UserWithRoles>? userRoles;

    protected override async Task OnInitializedAsync()
    {
        var users = UserManager.Users.ToList();
        userRoles = new List<UserWithRoles>();
        foreach (var user in users)
        {
            var roles = await UserManager.GetRolesAsync(user);
            userRoles.Add(new UserWithRoles
            {
                Email = user.Email ?? "(no email)",
                Roles = string.Join(", ", roles)
            });
        }
    }

    private sealed class UserWithRoles
    {
        public string Email { get; set; } = "";
        public string Roles { get; set; } = "";
    }
}

